import type {GroupFieldConfigs, IFormElement} from "@lmb-it/kitsconcerto-types";
import type {FieldValues, UseFormReturn} from "react-hook-form";

type Ctx = {
    control: any;
    getValues: any;
};

function isPromise<T = unknown>(v: unknown): v is Promise<T> {
    return (
        typeof v === "object" &&
        v !== null &&
        typeof (v as any).then === "function"
    );
}

export function dynamicList<T extends FieldValues>(
    element: IFormElement<T>,
    watchedValues: any[],
    allFormValues: T,
    groupField:GroupFieldConfigs<T>["groupField"],
    ctx: UseFormReturn<T,any,T>
): any[] {
    // No list → empty array
    if (!("list" in element)) return [];

    const { list, id } = element;

    // Static list
    if (Array.isArray(list)) {
        return list;
    }

    // Dynamic list
    if (typeof list === "function") {
        let result: unknown;

        try {
            result = list(watchedValues, allFormValues, ctx, groupField);
        } catch (err) {
            console.error(
                `[Form] list() threw an error for element "${id.toString()}"`,
                err
            );
            return [];
        }

        // Promise → NOT supported here
        if (isPromise(result)) {
            console.warn(
                `[Form] async list() is not supported. Element "${id.toString()}" must return an array synchronously.`
            );
            return [];
        }

        // Non-array return → invalid
        if (!Array.isArray(result)) {
            console.warn(
                `[Form] list() must return an array. Element "${id.toString()}" returned:`,
                result
            );
            return [];
        }

        return result;
    }

    // Anything else → invalid
    return [];
}
